use bpsw::is_prime;
use num_bigint::BigUint;

// --- 运行与测试 ---

fn main() {
    let test_cases = vec![
        ("2", true),
        ("17", true),
        ("561", false),        // 最小的卡迈克尔数
        ("2047", false),       // 第一个 Miller-Rabin Base 2 伪素数 (23 * 89)
        ("1194649", false),    // 著名的强 Lucas 伪素数
        ("2305843009213693951", true), // 梅森素数 2^61 - 1
        ("170141183460469231731687303715884105727", true),
        ("", true),
        ("",false)
    ];

    println!("{:<25} | {:<10} | {:<10}", "Number", "Expected", "Result");
    println!("{:-<50}", "");

    for (n_str, expected) in test_cases {
        let n = BigUint::parse_bytes(n_str.as_bytes(), 10).expect("Invalid number");
        let start = std::time::Instant::now();
        let result = is_prime(&n);
        let duration = start.elapsed();

        println!(
            "{:<25} | {:<10} | {:<10} ({:?})",
            n_str, expected, result, duration
        );
    }

    let n: BigUint = BigUint::new(vec![100003]);

    if is_prime(&n) {println!("{:?} is prime", n)} else {println!("{:?} is not prime", n)}
}
